package lec1;

public class max_of_three_number {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=7;
		int b=11;
		int c=10;
		if(a>b && a>c) {
			System.out.println(a+" is greater");
		}
		else if(b>c) {
			System.out.println(b+" is greater");
		}
		else {
			System.out.println(c+" is greater");
		}

	}

}
